function HolidayTable() {
  const tableData = Array.from({ length: 5 }, () => Array(5).fill(null));

  return (
    <div style={{ width: '33.33%' }}>
      <div className="overflow-x-auto bg-white rounded-lg shadow">
        <table className="min-w-full divide-y divide-gray-200 border-collapse">
          <tbody className="bg-white">
            {tableData.map((row, rowIndex) => (
              <tr key={`row-${rowIndex}`}>
                {row.map((_, colIndex) => {
                  if (colIndex === 0) {
                    return (
                      <td key={`cell-${rowIndex}-${colIndex}`} className="px-4 py-3 whitespace-nowrap text-sm font-semibold text-green-800 bg-green-100 border">
                        Header {rowIndex + 1}
                      </td>
                    );
                  }
                  return (
                    <td key={`cell-${rowIndex}-${colIndex}`} className="px-4 py-3 whitespace-nowrap text-sm font-semibold text-gray-900 border">
                      Cell
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default HolidayTable;
